
/*
  DilAvatar — Konuşan Asistan Avatarı / kullanıcı kalibrasyonlu sürüm
  Proje: DilHarita

  Tek dosyadır. HTML + CSS + SVG + vanilla JavaScript ile çalışır.
  Dış API, sunucu, paralı servis, harici kütüphane ve internet gerekmez.

  Ana kullanım:
    DilAvatar.mount("avatarHost");
    DilAvatar.speakText("merhaba bugün İngilizce çalışıyoruz", 3200);

  Ayar sayfası / kalibrasyon paneli:
    DilAvatar.mountControlPanel("avatarControls");

  Mantık:
    Ana avatar görselleri dosyaya gömülüdür.
    Ağız, göz kırpma ve kaş katmanları SVG overlay olarak ayrı çizilir.
    Kullanıcı ağız/göz/kaş koordinatlarını sliderlarla kendisi ayarlayabilir.
*/
(function(global){
  "use strict";

  var PREF_KEY = "dil-avatar-gender-v4";
  var CALIB_KEY = "dil-avatar-calibration-v4";
  var STYLE_ID = "dil-avatar-style-v4";

  var AVATAR_IMAGES = {"kadin": "data:image/jpeg;base64,", "erkek": "data:image/jpeg;base64,"};

  var AVATAR_LABELS = {
    kadin: "3D Avatar",
    erkek: "Vektör Avatar"
  };

  function clone(obj){ return JSON.parse(JSON.stringify(obj)); }
  function clamp(n, min, max){ n = Number(n); if(!isFinite(n)) n = 0; return Math.max(min, Math.min(max, n)); }
  function safeGet(key){ try{ return global.localStorage ? global.localStorage.getItem(key) : null; }catch(e){ return null; } }
  function safeSet(key, value){ try{ if(global.localStorage) global.localStorage.setItem(key, value); }catch(e){} }
  function safeRemove(key){ try{ if(global.localStorage) global.localStorage.removeItem(key); }catch(e){} }

  var DEFAULT_CONFIG = {
    kadin: {
      accent: "#3b82f6", accent2: "#2563eb",
      mouthX: 500, mouthY: 604, mouthScale: 0.58, mouthWidth: 74, mouthHeight: 62, mouthRotate: 0, mouthOpacity: 0.98,
      leftEyeX: 405, leftEyeY: 428, rightEyeX: 595, rightEyeY: 428,
      eyeW: 92, eyeH: 30, eyeStroke: 8, eyeCurve: 18,
      browVisible: false, browOpacity: 0.78, browWidth: 115, browHeight: 20, browPeak: 9, browThickness: 8,
      leftBrowX: 405, leftBrowY: 350, rightBrowX: 595, rightBrowY: 350, leftBrowRotate: -6, rightBrowRotate: 6,
      skin: "#efc2a6", eyelid: "#7a5260", browColor: "#7a3c1e", mouthLip: "#ef5f7e", mouthDark: "#301018"
    },
    erkek: {
      accent: "#2dd4bf", accent2: "#0e7490",
      mouthX: 502, mouthY: 515, mouthScale: 0.52, mouthWidth: 75, mouthHeight: 64, mouthRotate: 0, mouthOpacity: 0.96,
      leftEyeX: 418, leftEyeY: 363, rightEyeX: 584, rightEyeY: 363,
      eyeW: 76, eyeH: 22, eyeStroke: 7, eyeCurve: 15,
      browVisible: false, browOpacity: 0.75, browWidth: 105, browHeight: 18, browPeak: 8, browThickness: 8,
      leftBrowX: 418, leftBrowY: 314, rightBrowX: 584, rightBrowY: 314, leftBrowRotate: -5, rightBrowRotate: 5,
      skin: "#f1b174", eyelid: "#7a3e2b", browColor: "#5a2a18", mouthLip: "#b94a4f", mouthDark: "#451016"
    }
  };

  var state = {
    gender: "kadin",
    config: clone(DEFAULT_CONFIG),
    host: null, box: null, img: null, mouth: null, overlay: null, buttons: [],
    controlHost: null,
    timers: [], blinkTimer: null, speaking: false, thinking: false, shape: "rest"
  };

  function loadPref(){
    var g = safeGet(PREF_KEY);
    if(g === "kadin" || g === "erkek") state.gender = g;
    var raw = safeGet(CALIB_KEY);
    if(raw){
      try{
        var saved = JSON.parse(raw);
        ["kadin","erkek"].forEach(function(gender){
          if(saved && saved[gender]){
            Object.keys(DEFAULT_CONFIG[gender]).forEach(function(k){
              if(saved[gender][k] !== undefined) state.config[gender][k] = saved[gender][k];
            });
          }
        });
      }catch(e){}
    }
  }
  function savePref(){ safeSet(PREF_KEY, state.gender); }
  function saveCalibration(){ safeSet(CALIB_KEY, JSON.stringify(state.config)); }
  function currentConfig(){ return state.config[state.gender] || state.config.kadin; }

  function injectStyle(){
    if(document.getElementById(STYLE_ID)) return;
    var css = ""+
      ".dilav-wrap{display:flex;flex-direction:column;align-items:center;gap:10px;width:100%;max-width:260px;margin:auto;}"+
      ".dilav-box{position:relative;width:100%;aspect-ratio:1/1;border-radius:50%;overflow:hidden;border:3px solid var(--dilav-accent,#3b82f6);background:#0b1120;box-shadow:0 14px 34px rgba(0,0,0,.34),0 0 0 1px rgba(255,255,255,.08) inset;isolation:isolate;}"+
      ".dilav-img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;display:block;user-select:none;-webkit-user-drag:none;}"+
      ".dilav-overlay{position:absolute;inset:0;width:100%;height:100%;pointer-events:none;}"+
      ".dilav-mouth{transition:transform 80ms ease,opacity 80ms ease;transform-origin:center;}"+
      ".dilav-eyes-closed{opacity:0;transition:opacity 65ms ease;}"+
      ".dilav-blink .dilav-eyes-closed{opacity:1;}"+
      ".dilav-thinking-dot{opacity:0;animation:dilavThink 1.05s infinite ease-in-out;}"+
      ".dilav-thinking-dot:nth-child(2){animation-delay:.16s}.dilav-thinking-dot:nth-child(3){animation-delay:.32s}"+
      ".dilav-thinking-off .dilav-thinking-dot{display:none;}"+
      "@keyframes dilavThink{0%,80%,100%{opacity:.12;transform:translateY(0)}40%{opacity:.95;transform:translateY(-8px)}}"+
      ".dilav-switch{display:inline-flex;background:rgba(11,17,32,.78);border:1px solid rgba(255,255,255,.14);border-radius:999px;padding:4px;gap:4px;backdrop-filter:blur(8px);}"+
      ".dilav-switch button{border:0;border-radius:999px;padding:7px 12px;font:800 12px/1.1 system-ui,-apple-system,Segoe UI,Arial,sans-serif;cursor:pointer;background:transparent;color:#cbd5e1;white-space:nowrap;}"+
      ".dilav-switch button.is-active{background:var(--dilav-accent,#2563eb);color:#fff;box-shadow:0 4px 12px rgba(0,0,0,.25);}"+
      ".dilav-panel{width:100%;max-width:840px;margin:0 auto;padding:14px;border:1px solid rgba(148,163,184,.25);border-radius:18px;background:#0b1120;color:#e5e7eb;font-family:system-ui,-apple-system,Segoe UI,Arial,sans-serif;box-sizing:border-box;}"+
      ".dilav-panel *{box-sizing:border-box}.dilav-panel h2{margin:0 0 10px;font-size:19px}.dilav-panel p{margin:4px 0 12px;color:#94a3b8;font-size:13px}"+
      ".dilav-panel-top{display:flex;gap:8px;align-items:center;justify-content:space-between;flex-wrap:wrap;margin-bottom:12px}"+
      ".dilav-panel-actions{display:flex;gap:7px;flex-wrap:wrap}.dilav-panel-actions button,.dilav-mini-btn{border:1px solid rgba(148,163,184,.35);background:#111827;color:#e5e7eb;border-radius:10px;padding:8px 10px;font-weight:800;cursor:pointer;}"+
      ".dilav-panel-actions button:hover,.dilav-mini-btn:hover{background:#1f2937}"+
      ".dilav-groups{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px;}"+
      ".dilav-group{border:1px solid rgba(148,163,184,.22);border-radius:14px;padding:12px;background:rgba(15,23,42,.72)}"+
      ".dilav-group h3{margin:0 0 8px;font-size:15px;color:#bfdbfe}"+
      ".dilav-row{display:grid;grid-template-columns:150px 1fr 62px;gap:8px;align-items:center;margin:8px 0;}"+
      ".dilav-row label{font-size:12px;color:#cbd5e1}.dilav-row input[type=range]{width:100%;accent-color:var(--dilav-accent,#3b82f6)}.dilav-val{text-align:right;font-variant-numeric:tabular-nums;color:#fff;font-size:12px;}"+
      ".dilav-check{display:flex;align-items:center;gap:8px;margin:8px 0;color:#cbd5e1;font-size:13px}.dilav-check input{width:18px;height:18px;accent-color:var(--dilav-accent,#3b82f6)}"+
      ".dilav-test-buttons{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px}.dilav-test-buttons button{border:0;border-radius:999px;padding:7px 9px;font-size:12px;font-weight:800;background:#1e293b;color:#e2e8f0;cursor:pointer}.dilav-test-buttons button:hover{background:#334155}"+
      ".dilav-json{width:100%;min-height:84px;background:#020617;color:#dbeafe;border:1px solid rgba(148,163,184,.25);border-radius:12px;padding:10px;font:12px/1.35 ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;resize:vertical;}"+
      "@media(max-width:760px){.dilav-groups{grid-template-columns:1fr}.dilav-row{grid-template-columns:128px 1fr 50px}.dilav-wrap{max-width:210px}}";
    var style = document.createElement("style");
    style.id = STYLE_ID;
    style.textContent = css;
    document.head.appendChild(style);
  }

  function visemeForChar(ch){
    ch = String(ch || "").toLocaleLowerCase("tr-TR");
    if("aeâ".indexOf(ch) >= 0) return "open";
    if("ou".indexOf(ch) >= 0) return "round";
    if("ıiüöy".indexOf(ch) >= 0) return "wide";
    if("mbp".indexOf(ch) >= 0) return "closed";
    if("fv".indexOf(ch) >= 0) return "teeth";
    return "rest";
  }

  function mouthSvg(shape, cfg){
    var lip = cfg.mouthLip || "#ef5f7e";
    var dark = cfg.mouthDark || "#301018";
    var hi = "rgba(255,255,255,.55)";
    var op = clamp(cfg.mouthOpacity, 0, 1);
    if(shape === "open") return '<g opacity="'+op+'"><path d="M-75,-5 C-45,-36 45,-36 75,-5 C55,48 -55,48 -75,-5 Z" fill="'+lip+'"/><ellipse cx="0" cy="8" rx="42" ry="34" fill="'+dark+'"/><path d="M-42,-10 C-20,-22 20,-22 42,-10 C28,-2 -28,-2 -42,-10 Z" fill="#fff" opacity=".9"/><path d="M-38,31 C-14,44 16,44 39,31 C23,54 -24,54 -38,31 Z" fill="#ff8aa1" opacity=".86"/></g>';
    if(shape === "round") return '<g opacity="'+op+'"><ellipse cx="0" cy="0" rx="48" ry="40" fill="'+lip+'"/><ellipse cx="0" cy="2" rx="25" ry="28" fill="'+dark+'"/><path d="M-28,-28 C-8,-38 12,-38 30,-27" stroke="'+hi+'" stroke-width="8" stroke-linecap="round" opacity=".65"/></g>';
    if(shape === "wide") return '<g opacity="'+op+'"><path d="M-88,-6 C-46,-28 46,-28 88,-6 C58,28 -58,28 -88,-6 Z" fill="'+lip+'"/><path d="M-61,-5 C-30,-17 31,-17 61,-5 C42,10 -42,10 -61,-5 Z" fill="#fff" opacity=".92"/><path d="M-63,8 C-30,28 30,28 63,8 C38,36 -38,36 -63,8 Z" fill="'+dark+'" opacity=".78"/></g>';
    if(shape === "closed") return '<g opacity="'+op+'"><path d="M-70,0 C-40,-18 40,-18 70,0 C38,16 -38,16 -70,0 Z" fill="'+lip+'"/><path d="M-63,0 C-30,8 30,8 63,0" stroke="'+dark+'" stroke-width="7" stroke-linecap="round" fill="none" opacity=".72"/><path d="M-36,-9 C-13,-16 16,-16 38,-8" stroke="'+hi+'" stroke-width="5" stroke-linecap="round" opacity=".45"/></g>';
    if(shape === "teeth") return '<g opacity="'+op+'"><path d="M-76,-3 C-42,-24 42,-24 76,-3 C52,29 -52,29 -76,-3 Z" fill="'+lip+'"/><path d="M-48,-4 C-23,-15 24,-15 49,-4 L40,11 C17,18 -17,18 -40,11 Z" fill="#fff" opacity=".92"/><path d="M-56,11 C-30,31 30,31 56,11" stroke="'+dark+'" stroke-width="8" stroke-linecap="round" fill="none" opacity=".70"/></g>';
    return '<g opacity="'+op+'"><path d="M-70,0 C-39,20 39,20 70,0 C38,11 -38,11 -70,0 Z" fill="'+lip+'"/><path d="M-55,1 C-25,9 25,9 55,1" stroke="'+dark+'" stroke-width="5" stroke-linecap="round" fill="none" opacity=".56"/><path d="M-33,-4 C-13,-10 12,-10 34,-4" stroke="'+hi+'" stroke-width="5" stroke-linecap="round" opacity=".35"/></g>';
  }

  function mouthTransform(shape, cfg){
    var s = Number(cfg.mouthScale || 1);
    if(shape === "open") s *= 1.06;
    if(shape === "closed") s *= .96;
    if(shape === "wide") s *= 1.05;
    var sx = s * (Number(cfg.mouthWidth || 100) / 100);
    var sy = s * (Number(cfg.mouthHeight || 100) / 100);
    return "translate("+cfg.mouthX+" "+cfg.mouthY+") rotate("+(cfg.mouthRotate||0)+") scale("+sx+" "+sy+")";
  }

  function browPath(cfg){
    var w = Number(cfg.browWidth || 100), h = Number(cfg.browHeight || 18), p = Number(cfg.browPeak || 8);
    return "M"+(-w/2)+" 0 C"+(-w/4)+" "+(-h-p)+" "+(w/4)+" "+(-h-p)+" "+(w/2)+" 0";
  }

  function overlaySvg(cfg){
    var bw = cfg.browVisible ? 1 : 0;
    return ''+
      '<svg class="dilav-overlay dilav-thinking-off" viewBox="0 0 1000 1000" aria-hidden="true">'+
        '<defs><filter id="dilavSoft" x="-40%" y="-40%" width="180%" height="180%"><feGaussianBlur stdDeviation="1.8"/></filter><filter id="dilavShadow" x="-40%" y="-40%" width="180%" height="180%"><feDropShadow dx="0" dy="4" stdDeviation="3" flood-color="#000" flood-opacity=".24"/></filter></defs>'+
        '<g class="dilav-brows" opacity="'+(bw * clamp(cfg.browOpacity,0,1))+'">'+
          '<path d="'+browPath(cfg)+'" transform="translate('+cfg.leftBrowX+' '+cfg.leftBrowY+') rotate('+cfg.leftBrowRotate+')" stroke="'+cfg.browColor+'" stroke-width="'+cfg.browThickness+'" stroke-linecap="round" fill="none"/>'+ 
          '<path d="'+browPath(cfg)+'" transform="translate('+cfg.rightBrowX+' '+cfg.rightBrowY+') rotate('+cfg.rightBrowRotate+') scale(-1 1)" stroke="'+cfg.browColor+'" stroke-width="'+cfg.browThickness+'" stroke-linecap="round" fill="none"/>'+ 
        '</g>'+
        '<g class="dilav-eyes-closed">'+
          '<g transform="translate('+cfg.leftEyeX+' '+cfg.leftEyeY+')"><ellipse cx="0" cy="5" rx="'+(cfg.eyeW/2)+'" ry="'+(cfg.eyeH/2)+'" fill="'+cfg.skin+'" opacity=".92" filter="url(#dilavSoft)"/><path d="M-'+(cfg.eyeW/2-12)+' 6 C-'+(cfg.eyeW/4)+' '+cfg.eyeCurve+' '+(cfg.eyeW/4)+' '+cfg.eyeCurve+' '+(cfg.eyeW/2-12)+' 6" stroke="'+cfg.eyelid+'" stroke-width="'+cfg.eyeStroke+'" stroke-linecap="round" fill="none"/></g>'+
          '<g transform="translate('+cfg.rightEyeX+' '+cfg.rightEyeY+')"><ellipse cx="0" cy="5" rx="'+(cfg.eyeW/2)+'" ry="'+(cfg.eyeH/2)+'" fill="'+cfg.skin+'" opacity=".92" filter="url(#dilavSoft)"/><path d="M-'+(cfg.eyeW/2-12)+' 6 C-'+(cfg.eyeW/4)+' '+cfg.eyeCurve+' '+(cfg.eyeW/4)+' '+cfg.eyeCurve+' '+(cfg.eyeW/2-12)+' 6" stroke="'+cfg.eyelid+'" stroke-width="'+cfg.eyeStroke+'" stroke-linecap="round" fill="none"/></g>'+
        '</g>'+
        '<g class="dilav-mouth" filter="url(#dilavShadow)" transform="'+mouthTransform(state.shape, cfg)+'"></g>'+ 
        '<g class="dilav-thinking" transform="translate(500 120)"><circle class="dilav-thinking-dot" cx="-34" cy="0" r="10" fill="'+cfg.accent+'"/><circle class="dilav-thinking-dot" cx="0" cy="0" r="10" fill="'+cfg.accent+'"/><circle class="dilav-thinking-dot" cx="34" cy="0" r="10" fill="'+cfg.accent+'"/></g>'+ 
      '</svg>';
  }

  function clearSpeechTimers(){ for(var i=0;i<state.timers.length;i++) clearTimeout(state.timers[i]); state.timers = []; }

  function paintMouth(shape){
    if(!state.mouth) return;
    var allowed = {rest:1, open:1, round:1, wide:1, closed:1, teeth:1};
    shape = allowed[shape] ? shape : "rest";
    state.shape = shape;
    state.mouth.innerHTML = mouthSvg(shape, currentConfig());
    state.mouth.setAttribute("transform", mouthTransform(shape, currentConfig()));
  }

  function refreshOverlayOnly(){
    if(!state.box) return;
    var cfg = currentConfig();
    state.box.style.setProperty("--dilav-accent", cfg.accent);
    state.box.style.borderColor = cfg.accent;
    var oldThinking = state.overlay && !state.overlay.classList.contains("dilav-thinking-off");
    var oldBlink = state.box.classList.contains("dilav-blink");
    var img = state.box.querySelector(".dilav-img");
    state.box.innerHTML = '<img class="dilav-img" alt="DilHarita konuşan asistan avatarı" src="'+AVATAR_IMAGES[state.gender]+'">' + overlaySvg(cfg);
    state.img = state.box.querySelector(".dilav-img");
    state.overlay = state.box.querySelector(".dilav-overlay");
    state.mouth = state.box.querySelector(".dilav-mouth");
    if(oldThinking) state.overlay.classList.remove("dilav-thinking-off");
    if(oldBlink) state.box.classList.add("dilav-blink");
    paintMouth(state.shape || "rest");
  }

  function renderAvatar(){
    if(!state.box) return;
    refreshOverlayOnly();
    refreshButtons();
    refreshControlPanelValues();
  }

  function refreshButtons(){
    if(!state.buttons) return;
    for(var i=0;i<state.buttons.length;i++){
      var b = state.buttons[i];
      var on = b.getAttribute("data-g") === state.gender;
      if(on) b.classList.add("is-active"); else b.classList.remove("is-active");
    }
  }

  function blinkOnce(){
    if(!state.box) return;
    state.box.classList.add("dilav-blink");
    setTimeout(function(){ if(state.box) state.box.classList.remove("dilav-blink"); }, 145);
  }
  function startBlink(){
    stopBlink();
    function loop(){
      var delay = 2500 + Math.random() * 2500;
      state.blinkTimer = setTimeout(function(){ blinkOnce(); loop(); }, delay);
    }
    loop();
  }
  function stopBlink(){ if(state.blinkTimer){ clearTimeout(state.blinkTimer); state.blinkTimer = null; } }
  function setThinkingVisual(on){ var svg = state.box ? state.box.querySelector(".dilav-overlay") : null; if(!svg) return; if(on) svg.classList.remove("dilav-thinking-off"); else svg.classList.add("dilav-thinking-off"); }
  function setAvatar(g){ if(g !== "kadin" && g !== "erkek") return; state.gender = g; savePref(); renderAvatar(); }

  var CONTROL_DEFS = [
    {group:"Ağız", key:"mouthX", label:"Ağız X", min:300, max:700, step:1},
    {group:"Ağız", key:"mouthY", label:"Ağız Y", min:420, max:720, step:1},
    {group:"Ağız", key:"mouthScale", label:"Ağız ölçek", min:.20, max:1.30, step:.01},
    {group:"Ağız", key:"mouthWidth", label:"Ağız genişlik", min:25, max:180, step:1},
    {group:"Ağız", key:"mouthHeight", label:"Ağız yükseklik", min:25, max:180, step:1},
    {group:"Ağız", key:"mouthRotate", label:"Ağız açı", min:-25, max:25, step:1},
    {group:"Ağız", key:"mouthOpacity", label:"Ağız opaklık", min:0, max:1, step:.01},

    {group:"Göz kırpma", key:"leftEyeX", label:"Sol göz X", min:250, max:550, step:1},
    {group:"Göz kırpma", key:"leftEyeY", label:"Sol göz Y", min:250, max:550, step:1},
    {group:"Göz kırpma", key:"rightEyeX", label:"Sağ göz X", min:450, max:750, step:1},
    {group:"Göz kırpma", key:"rightEyeY", label:"Sağ göz Y", min:250, max:550, step:1},
    {group:"Göz kırpma", key:"eyeW", label:"Göz kapak genişlik", min:30, max:170, step:1},
    {group:"Göz kırpma", key:"eyeH", label:"Göz kapak yükseklik", min:8, max:80, step:1},
    {group:"Göz kırpma", key:"eyeStroke", label:"Kapak çizgi kalınlığı", min:1, max:20, step:1},
    {group:"Göz kırpma", key:"eyeCurve", label:"Kapak eğrisi", min:0, max:45, step:1},

    {group:"Kaş", key:"browOpacity", label:"Kaş opaklık", min:0, max:1, step:.01},
    {group:"Kaş", key:"browWidth", label:"Kaş genişlik", min:30, max:180, step:1},
    {group:"Kaş", key:"browHeight", label:"Kaş yükseklik", min:-20, max:55, step:1},
    {group:"Kaş", key:"browPeak", label:"Kaş tepe noktası", min:-20, max:45, step:1},
    {group:"Kaş", key:"browThickness", label:"Kaş kalınlık", min:1, max:20, step:1},
    {group:"Kaş", key:"leftBrowX", label:"Sol kaş X", min:250, max:550, step:1},
    {group:"Kaş", key:"leftBrowY", label:"Sol kaş Y", min:220, max:470, step:1},
    {group:"Kaş", key:"rightBrowX", label:"Sağ kaş X", min:450, max:750, step:1},
    {group:"Kaş", key:"rightBrowY", label:"Sağ kaş Y", min:220, max:470, step:1},
    {group:"Kaş", key:"leftBrowRotate", label:"Sol kaş açı", min:-40, max:40, step:1},
    {group:"Kaş", key:"rightBrowRotate", label:"Sağ kaş açı", min:-40, max:40, step:1}
  ];

  function groupedDefs(){
    var groups = {};
    CONTROL_DEFS.forEach(function(d){ if(!groups[d.group]) groups[d.group] = []; groups[d.group].push(d); });
    return groups;
  }

  function makeControlRow(def, cfg){
    var val = cfg[def.key];
    return '<div class="dilav-row" data-key="'+def.key+'"><label>'+def.label+'</label><input type="range" min="'+def.min+'" max="'+def.max+'" step="'+def.step+'" value="'+val+'"><span class="dilav-val">'+val+'</span></div>';
  }

  function buildControlPanel(){
    if(!state.controlHost) return;
    var cfg = currentConfig();
    var groups = groupedDefs();
    var html = ''+
      '<div class="dilav-panel" style="--dilav-accent:'+cfg.accent+'">'+
        '<div class="dilav-panel-top"><div><h2>Avatar ayarlama paneli</h2><p>Kayma olursa ağız, göz kırpma ve kaş katmanlarını buradan canlı ayarla. Değerler tarayıcıda güvenli şekilde saklanır.</p></div>'+
        '<div class="dilav-panel-actions"><button type="button" data-act="blink">Göz test</button><button type="button" data-act="speak">Konuşma test</button><button type="button" data-act="reset">Bu avatarı sıfırla</button></div></div>'+
        '<label class="dilav-check"><input type="checkbox" data-key="browVisible" '+(cfg.browVisible?'checked':'')+'> Ayarlanabilir kaş katmanını göster</label>'+
        '<div class="dilav-test-buttons"><button type="button" data-mouth="rest">rest</button><button type="button" data-mouth="open">open</button><button type="button" data-mouth="round">round</button><button type="button" data-mouth="wide">wide</button><button type="button" data-mouth="closed">closed</button><button type="button" data-mouth="teeth">teeth</button></div>'+
        '<div class="dilav-groups">';
    Object.keys(groups).forEach(function(g){
      html += '<section class="dilav-group"><h3>'+g+'</h3>';
      groups[g].forEach(function(def){ html += makeControlRow(def, cfg); });
      html += '</section>';
    });
    html += '</div>'+
      '<section class="dilav-group" style="margin-top:12px"><h3>Ayar JSON aktar / al</h3><textarea class="dilav-json" spellcheck="false"></textarea><div class="dilav-panel-actions" style="margin-top:8px"><button type="button" data-act="export">JSON getir</button><button type="button" data-act="import">JSON yükle</button><button type="button" data-act="resetAll">Tüm avatarları sıfırla</button></div></section>'+
      '</div>';
    state.controlHost.innerHTML = html;
    bindControlPanel();
  }

  function bindControlPanel(){
    if(!state.controlHost) return;
    var panel = state.controlHost.querySelector(".dilav-panel");
    if(!panel) return;
    panel.style.setProperty("--dilav-accent", currentConfig().accent);
    Array.prototype.slice.call(panel.querySelectorAll(".dilav-row")).forEach(function(row){
      var key = row.getAttribute("data-key"), input = row.querySelector("input"), val = row.querySelector(".dilav-val");
      input.oninput = function(){
        var n = Number(input.value);
        state.config[state.gender][key] = n;
        val.textContent = input.value;
        saveCalibration();
        refreshOverlayOnly();
      };
    });
    var browCheck = panel.querySelector('input[data-key="browVisible"]');
    if(browCheck){
      browCheck.onchange = function(){
        state.config[state.gender].browVisible = !!browCheck.checked;
        saveCalibration();
        refreshOverlayOnly();
      };
    }
    Array.prototype.slice.call(panel.querySelectorAll("button[data-mouth]")).forEach(function(btn){ btn.onclick = function(){ paintMouth(btn.getAttribute("data-mouth")); }; });
    Array.prototype.slice.call(panel.querySelectorAll("button[data-act]")).forEach(function(btn){
      btn.onclick = function(){
        var act = btn.getAttribute("data-act");
        if(act === "blink") blinkOnce();
        if(act === "speak") API.speakText("merhaba bugün İngilizce çalışıyoruz", 3200);
        if(act === "reset") { state.config[state.gender] = clone(DEFAULT_CONFIG[state.gender]); saveCalibration(); renderAvatar(); buildControlPanel(); }
        if(act === "resetAll") { state.config = clone(DEFAULT_CONFIG); safeRemove(CALIB_KEY); renderAvatar(); buildControlPanel(); }
        if(act === "export") { var ta = panel.querySelector(".dilav-json"); if(ta) ta.value = API.exportCalibration(); }
        if(act === "import") { var ta2 = panel.querySelector(".dilav-json"); if(ta2) { try{ API.importCalibration(ta2.value); }catch(e){ alert("JSON okunamadı: "+e.message); } } }
      };
    });
  }

  function refreshControlPanelValues(){
    if(!state.controlHost) return;
    buildControlPanel();
  }

  var API = {
    mount: function(elIdVeyaEleman){
      loadPref(); injectStyle();
      var host = (typeof elIdVeyaEleman === "string") ? document.getElementById(elIdVeyaEleman) : elIdVeyaEleman;
      if(!host) return null;
      state.host = host;
      host.innerHTML = '<div class="dilav-wrap"><div class="dilav-box" role="img" aria-label="Konuşan asistan avatarı"></div><div class="dilav-switch" aria-label="Avatar seçimi"><button type="button" data-g="kadin">'+AVATAR_LABELS.kadin+'</button><button type="button" data-g="erkek">'+AVATAR_LABELS.erkek+'</button></div></div>';
      state.box = host.querySelector(".dilav-box");
      state.buttons = Array.prototype.slice.call(host.querySelectorAll(".dilav-switch button"));
      state.buttons.forEach(function(b){ b.onclick = function(){ setAvatar(this.getAttribute("data-g")); }; });
      state.shape = "rest";
      renderAvatar();
      startBlink();
      return state.box;
    },

    mountControlPanel: function(elIdVeyaEleman){
      loadPref(); injectStyle();
      var host = (typeof elIdVeyaEleman === "string") ? document.getElementById(elIdVeyaEleman) : elIdVeyaEleman;
      if(!host) return null;
      state.controlHost = host;
      buildControlPanel();
      return host;
    },

    setMouth: function(shape){ clearSpeechTimers(); state.speaking=false; state.thinking=false; setThinkingVisual(false); paintMouth(shape || "rest"); },

    speakText: function(text, durationMs){
      if(!state.box) return;
      clearSpeechTimers(); state.speaking=true; state.thinking=false; setThinkingVisual(false);
      var chars = Array.from(String(text || ""));
      if(!chars.length){ paintMouth("rest"); state.speaking=false; return; }
      var total = durationMs ? Number(durationMs) : chars.length * 110;
      if(!isFinite(total) || total <= 0) total = chars.length * 110;
      var step = clamp(Math.round(total / chars.length), 60, 150);
      chars.forEach(function(ch, index){
        state.timers.push(setTimeout(function(){ paintMouth(visemeForChar(ch)); if(index % 11 === 0) blinkOnce(); }, index * step));
      });
      state.timers.push(setTimeout(function(){ paintMouth("rest"); state.speaking=false; }, chars.length * step + 90));
    },

    thinking: function(on){
      if(!state.box) return;
      clearSpeechTimers(); state.thinking=!!on; state.speaking=false; setThinkingVisual(!!on);
      if(on){ var i=0; (function pulse(){ if(!state.thinking) return; paintMouth(i%2 ? "closed" : "rest"); i++; state.timers.push(setTimeout(pulse,420)); })(); }
      else paintMouth("rest");
    },

    stop: function(){ clearSpeechTimers(); state.speaking=false; state.thinking=false; setThinkingVisual(false); paintMouth("rest"); },
    setGender: function(g){ setAvatar(g); },
    getGender: function(){ return state.gender; },
    setAvatarStyle: function(style){ if(style === "3d" || style === "doll" || style === "oyuncak") setAvatar("kadin"); else if(style === "vector" || style === "vektor" || style === "profesyonel") setAvatar("erkek"); },
    getAvatarStyle: function(){ return state.gender === "kadin" ? "3d" : "vector"; },
    visemeForChar: visemeForChar,
    blink: blinkOnce,

    getCalibration: function(){ return clone(state.config); },
    setCalibration: function(partial){
      if(!partial) return;
      ["kadin","erkek"].forEach(function(g){ if(partial[g]) Object.keys(partial[g]).forEach(function(k){ if(state.config[g] && state.config[g][k] !== undefined) state.config[g][k] = partial[g][k]; }); });
      saveCalibration(); renderAvatar();
    },
    exportCalibration: function(){ return JSON.stringify(state.config, null, 2); },
    importCalibration: function(json){ var obj = (typeof json === "string") ? JSON.parse(json) : json; API.setCalibration(obj); buildControlPanel(); },
    resetCalibration: function(scope){ if(scope === "all"){ state.config = clone(DEFAULT_CONFIG); safeRemove(CALIB_KEY); } else { state.config[state.gender] = clone(DEFAULT_CONFIG[state.gender]); saveCalibration(); } renderAvatar(); buildControlPanel(); }
  };

  global.DilAvatar = API;
})(window);
